CREATE TABLE `common_notify`( `id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID', `type` tinyint(2) NOT NULL COMMENT '通知类型 1：excel导出', `title` varchar(30) NOT NULL COMMENT '标题', `content` varchar(255) DEFAULT NULL COMMENT '内容', `link_url` varchar(255) DEFAULT NULL COMMENT '跳转地址', `read_status` tinyint(2) NOT NULL DEFAULT '0' COMMENT '阅读状态 0：未阅读 1：已阅读', `to_user_id` bigint NOT NULL COMMENT '需要推送通知的用户ID', `is_push` tinyint(1) DEFAULT '0' COMMENT '是否已推送 1：已推送 0：未推送', `create_user_id` bigint NOT NULL COMMENT '创建人ID', `create_user_name` varchar(30) NOT NULL COMMENT '创建人名称', `create_time` datetime(3) DEFAULT NULL COMMENT '创建日期', `update_user_id` bigint DEFAULT NULL COMMENT '修改人ID', `update_user_name` varchar(30) DEFAULT NULL COMMENT '修改人名称', `update_time` datetime(3) DEFAULT NULL COMMENT '修改时间', `is_del` tinyint(1) DEFAULT '0' COMMENT '是否删除 1：已删除 0：未删除', PRIMARY KEY (`id`) USING BTREE) ENGINE=InnoDB AUTO_INCREMENT=1 DEFAULT CHARSET=utf8mb4 COMMENT='通知表';
